import { useState, useEffect } from "react";
import { useAuth } from "@/hooks/use-auth";
import { useWallet } from "@/hooks/use-wallet";
import { useStaking } from "@/hooks/use-staking";
import { CyberCard } from "@/components/CyberCard";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ArrowRight, Wallet as WalletIcon, Coins, Activity, Send, Loader2, Copy, Check, ArrowUpRight, ArrowDownLeft, Gem, Globe, Link2, ExternalLink, QrCode, X, TrendingUp, Lock, Unlock } from "lucide-react";
import { useLocation } from "wouter";
import { useToast } from "@/hooks/use-toast";
import { useQuery } from "@tanstack/react-query";
import { api } from "@shared/routes";
import { formatDistanceToNow } from "date-fns";
import { QRCodeSVG } from "qrcode.react";
import { TwoFactorSettings } from "@/components/TwoFactorSettings";
import { PriceTicker, wEBDtoUSD, formatUSD } from "@/components/PriceTicker";

export default function Wallet() {
  const [_, setLocation] = useLocation();
  const { user } = useAuth();
  const { wallet, transfer, isTransferring } = useWallet();
  const {
    stakingInfo, networkStats, isLoadingInfo,
    stake, unstake, claimRewards,
    isStaking, isUnstaking, isClaiming,
  } = useStaking();
  const { toast } = useToast();

  const [recipient, setRecipient] = useState("");
  const [amount, setAmount] = useState("");
  const [stakeAmount, setStakeAmount] = useState("");
  const [unstakeAmount, setUnstakeAmount] = useState("");
  const [copied, setCopied] = useState(false);
  const [showQR, setShowQR] = useState(false);

  const searchParams = new URLSearchParams(window.location.search);
  const purchaseSuccess = searchParams.get("purchase") === "success";
  const purchaseAmount = searchParams.get("amount");

  useEffect(() => {
    if (purchaseSuccess) {
      const amountStr = purchaseAmount ? `${Number(purchaseAmount).toLocaleString()} WEBD` : 'WEBD tokens';
      toast({
        title: "Purchase Successful",
        description: `${amountStr} have been credited to your wallet.`,
      });
      window.history.replaceState({}, "", "/wallet");
    }
  }, [purchaseSuccess]);

  const { data: myTransactions } = useQuery({
    queryKey: [api.transactions.mine.path],
    queryFn: async () => {
      const res = await fetch(api.transactions.mine.path);
      if (!res.ok) return [];
      return await res.json();
    },
    refetchInterval: 10000,
  });

  const { data: blockchainStatus } = useQuery({
    queryKey: ["/api/blockchain/status"],
    queryFn: async () => {
      const res = await fetch("/api/blockchain/status");
      if (!res.ok) return null;
      return await res.json();
    },
    refetchInterval: 30000,
  });

  const { data: polygonInfo } = useQuery({
    queryKey: ["/api/wallet/polygon-info"],
    queryFn: async () => {
      const res = await fetch("/api/wallet/polygon-info");
      if (!res.ok) return null;
      return await res.json();
    },
    enabled: !!user,
  });

  useEffect(() => {
    if (!user) {
      setLocation("/auth");
    }
  }, [user, setLocation]);

  const copyAddress = () => {
    if (wallet?.walletAddress) {
      navigator.clipboard.writeText(wallet.walletAddress);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const handleTransfer = () => {
    transfer({ recipientAddress: recipient, amount });
    setRecipient("");
    setAmount("");
  };

  const handleStake = () => {
    if (!stakeAmount) return;
    stake(stakeAmount);
    setStakeAmount("");
  };

  const handleUnstake = () => {
    if (!unstakeAmount) return;
    unstake(unstakeAmount);
    setUnstakeAmount("");
  };

  const stakedNum = parseFloat(stakingInfo?.stakedBalance || "0");
  const pendingRewardsNum = parseFloat(stakingInfo?.pendingRewards || "0");
  const apyNum = stakingInfo?.apy || 0;
  const totalNetworkStakedNum = parseFloat(stakingInfo?.totalNetworkStaked || "0");

  return (
    <div className="container mx-auto px-4 py-8 space-y-8">

      <div className="flex flex-col md:flex-row justify-between items-start md:items-end border-b border-primary/20 pb-6 gap-4">
        <div>
          <h1 className="text-4xl font-heading text-white" data-testid="text-wallet-title">WALLET DASHBOARD</h1>
          <div className="flex items-center gap-2 mt-2">
            <p className="font-mono text-primary/60 text-sm truncate max-w-xs" data-testid="text-wallet-address">
              {wallet?.walletAddress || "Loading..."}
            </p>
            <button onClick={copyAddress} className="text-muted-foreground hover:text-primary transition-colors" data-testid="button-copy-address">
              {copied ? <Check className="w-4 h-4 text-accent" /> : <Copy className="w-4 h-4" />}
            </button>
            <button onClick={() => setShowQR(!showQR)} className="text-muted-foreground hover:text-accent transition-colors" data-testid="button-show-qr">
              <QrCode className="w-4 h-4" />
            </button>
          </div>
          {showQR && wallet?.walletAddress && (
            <div className="mt-3 bg-white rounded-md p-4 w-fit relative">
              <button onClick={() => setShowQR(false)} className="absolute top-1 right-1 text-gray-500 hover:text-gray-800" data-testid="button-close-qr">
                <X className="w-4 h-4" />
              </button>
              <QRCodeSVG value={wallet.walletAddress} size={160} level="M" />
              <div className="text-center mt-2 text-[10px] text-gray-500 font-mono">Scan to receive WEBD</div>
            </div>
          )}
          {polygonInfo?.primaryPolygonAddress && (
            <div className="flex items-center gap-2 mt-1">
              <Globe className="w-3 h-3 text-purple-400" />
              <p className="font-mono text-purple-400/70 text-xs truncate max-w-xs" data-testid="text-polygon-address">
                {polygonInfo.primaryPolygonAddress}
              </p>
              <button
                onClick={() => { navigator.clipboard.writeText(polygonInfo.primaryPolygonAddress); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
                className="text-muted-foreground hover:text-purple-400 transition-colors"
                data-testid="button-copy-polygon-address"
              >
                <Copy className="w-3 h-3" />
              </button>
              <a
                href={`${polygonInfo.polygonscanUrl || 'https://amoy.polygonscan.com'}/address/${polygonInfo.primaryPolygonAddress}`}
                target="_blank"
                rel="noopener noreferrer"
                className="text-purple-400/60 hover:text-purple-300 transition-colors"
                data-testid="link-polygonscan-address"
              >
                <ExternalLink className="w-3 h-3" />
              </a>
            </div>
          )}
        </div>
        <div className="text-right">
          <div className="text-sm font-mono text-muted-foreground">AVAILABLE BALANCE</div>
          <div className="text-5xl font-mono text-accent text-gold-glow" data-testid="text-balance">
            {Number(wallet?.balance || 0).toLocaleString(undefined, { minimumFractionDigits: 4 })} <span className="text-lg text-primary">WEBD</span>
          </div>
          <div className="text-sm font-mono text-muted-foreground mt-0.5" data-testid="text-balance-usd">
            {formatUSD(wEBDtoUSD(Number(wallet?.balance || 0) + stakedNum))} USD
          </div>
          {stakedNum > 0 && (
            <div className="text-sm font-mono text-primary/60 mt-1" data-testid="text-staked-balance-header">
              + {stakedNum.toLocaleString(undefined, { minimumFractionDigits: 4 })} <span className="text-xs">MINING</span>
            </div>
          )}
          {polygonInfo?.maticBalance && parseFloat(polygonInfo.maticBalance) > 0 && (
            <div className="text-sm font-mono text-purple-400/80 mt-1" data-testid="text-matic-balance">
              {parseFloat(polygonInfo.maticBalance).toFixed(4)} <span className="text-xs text-purple-400/50">POL (on-chain)</span>
            </div>
          )}
          {blockchainStatus?.connected && (
            <div className="flex items-center justify-end gap-2 mt-2" data-testid="text-blockchain-status">
              <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse" />
              <span className="text-xs font-mono text-green-400/80">{blockchainStatus.network}</span>
              <span className="text-xs font-mono text-muted-foreground">Block #{blockchainStatus.blockNumber?.toLocaleString()}</span>
            </div>
          )}
          <div className="mt-2">
            <PriceTicker />
          </div>
        </div>
      </div>

      <div className="grid lg:grid-cols-2 gap-8">

        <CyberCard title="SEND WEBD" className="h-full">
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-mono text-primary/70">RECIPIENT ADDRESS</label>
              <Input
                value={recipient}
                onChange={(e) => setRecipient(e.target.value)}
                className="bg-input border-primary/30 font-mono"
                placeholder="WEBD$..."
                data-testid="input-recipient"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-mono text-primary/70">AMOUNT (WEBD)</label>
              <Input
                type="number"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                className="bg-input border-primary/30 font-mono text-xl"
                placeholder="0.00"
                data-testid="input-amount"
              />
            </div>
            <Button
              className="w-full btn-neon flex justify-between items-center group"
              disabled={isTransferring || !amount || !recipient}
              onClick={handleTransfer}
              data-testid="button-transfer"
            >
              <span>{isTransferring ? "BROADCASTING..." : "EXECUTE TRANSFER"}</span>
              {!isTransferring && <ArrowRight className="group-hover:translate-x-1 transition-transform" />}
            </Button>
          </div>
        </CyberCard>

        <CyberCard title="PoS MINING" className="h-full flex flex-col">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
            <div className="bg-background p-3 border border-primary/10 rounded-md">
              <div className="text-xs text-muted-foreground">MINING STAKE</div>
              <div className="text-xl font-mono text-white" data-testid="text-staked-balance">
                {stakedNum > 0 ? stakedNum.toLocaleString(undefined, { maximumFractionDigits: 2 }) : "0"}
              </div>
              <div className="text-[10px] text-muted-foreground">WEBD mining</div>
            </div>
            <div className="bg-background p-3 border border-primary/10 rounded-md">
              <div className="text-xs text-muted-foreground">MINING REWARDS</div>
              <div className="text-xl font-mono text-accent" data-testid="text-pending-rewards">
                {pendingRewardsNum > 0 ? pendingRewardsNum.toLocaleString(undefined, { maximumFractionDigits: 4 }) : "0"}
              </div>
              <div className="text-[10px] text-muted-foreground">WEBD mined</div>
            </div>
            <div className="bg-background p-3 border border-primary/10 rounded-md">
              <div className="text-xs text-muted-foreground">EST. APY</div>
              <div className="text-xl font-mono text-green-400" data-testid="text-apy">
                {apyNum > 0 ? `${apyNum.toLocaleString(undefined, { maximumFractionDigits: 1 })}%` : "--"}
              </div>
              <div className="text-[10px] text-muted-foreground">annual yield</div>
            </div>
            <div className="bg-background p-3 border border-primary/10 rounded-md">
              <div className="text-xs text-muted-foreground">NETWORK MINING</div>
              <div className="text-xl font-mono text-white" data-testid="text-network-staked">
                {totalNetworkStakedNum > 0 ? totalNetworkStakedNum.toLocaleString(undefined, { maximumFractionDigits: 0 }) : "0"}
              </div>
              <div className="text-[10px] text-muted-foreground">total WEBD staked</div>
            </div>
          </div>

          {stakedNum > 0 && (
            <div className="mb-3 p-2 border border-accent/20 rounded-md bg-accent/5">
              <div className="flex items-center gap-2 mb-1">
                <TrendingUp className="w-3 h-3 text-accent animate-pulse" />
                <span className="text-xs font-mono text-accent">MINING ACTIVE</span>
              </div>
              <div className="text-[10px] font-mono text-muted-foreground">
                Your {stakedNum.toLocaleString()} WEBD is mining rewards. Rewards accrue every 30 seconds based on your share of the total network mining power.
              </div>
            </div>
          )}

          {pendingRewardsNum > 0.0001 && (
            <Button
              className="w-full mb-3 btn-gold"
              onClick={claimRewards}
              disabled={isClaiming}
              data-testid="button-claim-rewards"
            >
              {isClaiming ? (
                <span className="flex items-center"><Loader2 className="animate-spin mr-2" /> CLAIMING...</span>
              ) : (
                <span className="flex items-center"><Gem className="mr-2" /> CLAIM {pendingRewardsNum.toFixed(4)} WEBD REWARDS</span>
              )}
            </Button>
          )}

          <div className="space-y-3">
            <div className="space-y-2">
              <label className="text-xs font-mono text-primary/70">START MINING (min 10 WEBD)</label>
              <div className="flex gap-2">
                <Input
                  type="number"
                  value={stakeAmount}
                  onChange={(e) => setStakeAmount(e.target.value)}
                  className="bg-input border-primary/30 font-mono flex-1"
                  placeholder="Amount to mine with"
                  data-testid="input-stake-amount"
                />
                <Button
                  onClick={handleStake}
                  disabled={isStaking || !stakeAmount || parseFloat(stakeAmount) < 10}
                  data-testid="button-stake"
                >
                  {isStaking ? <Loader2 className="animate-spin" /> : <Lock className="mr-1 w-4 h-4" />}
                  MINE
                </Button>
              </div>
            </div>

            {stakedNum > 0 && (
              <div className="space-y-2">
                <label className="text-xs font-mono text-primary/70">STOP MINING</label>
                <div className="flex gap-2">
                  <Input
                    type="number"
                    value={unstakeAmount}
                    onChange={(e) => setUnstakeAmount(e.target.value)}
                    className="bg-input border-primary/30 font-mono flex-1"
                    placeholder="Amount to withdraw"
                    data-testid="input-unstake-amount"
                  />
                  <Button
                    variant="outline"
                    onClick={handleUnstake}
                    disabled={isUnstaking || !unstakeAmount || parseFloat(unstakeAmount) <= 0}
                    data-testid="button-unstake"
                  >
                    {isUnstaking ? <Loader2 className="animate-spin" /> : <Unlock className="mr-1 w-4 h-4" />}
                    WITHDRAW
                  </Button>
                </div>
              </div>
            )}
          </div>

          {!stakedNum && (
            <div className="mt-4 font-mono text-xs text-muted-foreground italic p-3 border border-primary/10 rounded-md">
              Lock your WEBD tokens to start mining and earn passive rewards. The more you put in, the bigger your share of the mining rewards pool.
            </div>
          )}
        </CyberCard>
      </div>

      <TwoFactorSettings />

      <CyberCard title="TRANSACTION HISTORY" className="mt-0">
        <div className="overflow-x-auto">
          <table className="w-full font-mono text-sm text-left">
            <thead>
              <tr className="border-b border-primary/30 text-primary/70">
                <th className="py-3 px-2">TYPE</th>
                <th className="py-3 px-2">DETAILS</th>
                <th className="py-3 px-2 text-right">AMOUNT</th>
                <th className="py-3 px-2 text-right hidden sm:table-cell">TIME</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-primary/10">
              {myTransactions?.map((tx: any) => {
                const isSender = tx.senderId === user?.id;
                const isStakingReward = tx.type === "staking_reward";
                const isMiningReward = tx.type === "mining_reward";
                const isReward = isStakingReward || isMiningReward;
                const isConversion = tx.type === "conversion";
                const isPurchase = tx.type === "purchase";

                return (
                  <tr key={tx.id} className="hover:bg-primary/5 transition-colors" data-testid={`my-tx-row-${tx.id}`}>
                    <td className="py-3 px-2">
                      <div className="flex items-center gap-2">
                        {isPurchase ? (
                          <Coins className="w-4 h-4 text-green-400" />
                        ) : isReward ? (
                          <Gem className="w-4 h-4 text-accent" />
                        ) : isSender ? (
                          <ArrowUpRight className="w-4 h-4 text-red-400" />
                        ) : (
                          <ArrowDownLeft className="w-4 h-4 text-green-400" />
                        )}
                        <span className={`text-xs uppercase ${
                          isPurchase ? 'text-green-400' :
                          isReward ? 'text-accent' :
                          isConversion ? 'text-yellow-400' :
                          isSender ? 'text-red-400' : 'text-green-400'
                        }`}>
                          {isPurchase ? 'PURCHASED' :
                           isStakingReward ? 'MINED' :
                           isMiningReward ? 'MINED' :
                           isConversion ? 'CONVERTED' :
                           isSender ? 'SENT' : 'RECEIVED'}
                        </span>
                      </div>
                    </td>
                    <td className="py-3 px-2 text-muted-foreground text-xs truncate max-w-[150px] sm:max-w-[250px]">
                      {isPurchase ? 'Token purchase (Stripe)' :
                       isStakingReward ? 'Mining reward (PoS)' :
                       isMiningReward ? 'Block reward' :
                       isConversion ? 'Legacy swap' :
                       isSender ? `To ${tx.receiverAddress ? tx.receiverAddress.substring(0, 16) + '...' : 'Unknown'}` :
                       `From ${tx.senderAddress ? tx.senderAddress.substring(0, 16) + '...' : 'System'}`}
                    </td>
                    <td className={`py-3 px-2 text-right font-bold ${isSender && !isReward && !isPurchase ? 'text-red-400' : 'text-accent'}`}>
                      {isSender && !isReward && !isPurchase ? '-' : '+'}
                      {Number(tx.amount).toLocaleString(undefined, { minimumFractionDigits: 4 })} WEBD
                    </td>
                    <td className="py-3 px-2 text-right text-muted-foreground text-xs hidden sm:table-cell">
                      {tx.timestamp ? formatDistanceToNow(new Date(tx.timestamp), { addSuffix: true }) : ''}
                    </td>
                  </tr>
                );
              })}
              {(!myTransactions || myTransactions.length === 0) && (
                <tr>
                  <td colSpan={4} className="py-8 text-center text-muted-foreground">
                    No transactions yet. Start mining or receive tokens to see activity here.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </CyberCard>

    </div>
  );
}

