import { ethers } from "ethers";

const USE_TESTNET = true;

const WDOLLAR2_TOKEN_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function totalSupply() view returns (uint256)",
  "function balanceOf(address) view returns (uint256)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function transferFrom(address from, address to, uint256 amount) returns (bool)",
  "function mint(address to, uint256 amount)",
  "function owner() view returns (address)",
  "event Transfer(address indexed from, address indexed to, uint256 value)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)"
];

const WDOLLAR2_TOKEN_BYTECODE = "";

let provider: ethers.JsonRpcProvider | null = null;
let contractAddress: string | null = null;

function getRpcUrl(): string {
  const key = process.env.ALCHEMY_API_KEY;
  if (USE_TESTNET) {
    return `https://polygon-amoy.g.alchemy.com/v2/${key}`;
  }
  return `https://polygon-mainnet.g.alchemy.com/v2/${key}`;
}

export function getProvider(): ethers.JsonRpcProvider {
  if (!provider) {
    provider = new ethers.JsonRpcProvider(getRpcUrl());
  }
  return provider;
}

export function derivePolygonAddress(privateKeyHex: string): string {
  const wallet = new ethers.Wallet(privateKeyHex);
  return wallet.address;
}

export function getWalletSigner(privateKeyHex: string): ethers.Wallet {
  return new ethers.Wallet(privateKeyHex, getProvider());
}

export function setContractAddress(address: string) {
  contractAddress = address;
}

export function getContractAddress(): string | null {
  return contractAddress;
}

export function getTokenContract(signerOrProvider?: ethers.Signer | ethers.Provider): ethers.Contract | null {
  if (!contractAddress) return null;
  return new ethers.Contract(
    contractAddress,
    WDOLLAR2_TOKEN_ABI,
    signerOrProvider || getProvider()
  );
}

export async function getOnChainBalance(polygonAddress: string): Promise<string> {
  const contract = getTokenContract();
  if (!contract) return "0";
  try {
    const balance = await contract.balanceOf(polygonAddress);
    return ethers.formatUnits(balance, 18);
  } catch {
    return "0";
  }
}

export async function getMaticBalance(polygonAddress: string): Promise<string> {
  try {
    const balance = await getProvider().getBalance(polygonAddress);
    return ethers.formatEther(balance);
  } catch {
    return "0";
  }
}

export async function deployToken(deployerPrivateKey: string): Promise<string> {
  const signer = getWalletSigner(deployerPrivateKey);
  const factory = new ethers.ContractFactory(
    WDOLLAR2_TOKEN_ABI,
    WDOLLAR2_TOKEN_BYTECODE,
    signer
  );

  const contract = await factory.deploy();
  await contract.waitForDeployment();
  const address = await contract.getAddress();
  contractAddress = address;
  return address;
}

export async function transferTokens(
  senderPrivateKey: string,
  recipientAddress: string,
  amount: string
): Promise<string> {
  const signer = getWalletSigner(senderPrivateKey);
  const contract = getTokenContract(signer);
  if (!contract) throw new Error("Token contract not deployed");

  const amountWei = ethers.parseUnits(amount, 18);
  const tx = await contract.transfer(recipientAddress, amountWei);
  const receipt = await tx.wait();
  return receipt.hash;
}

export async function mintTokens(
  ownerPrivateKey: string,
  recipientAddress: string,
  amount: string
): Promise<string> {
  const signer = getWalletSigner(ownerPrivateKey);
  const contract = getTokenContract(signer);
  if (!contract) throw new Error("Token contract not deployed");

  const amountWei = ethers.parseUnits(amount, 18);
  const tx = await contract.mint(recipientAddress, amountWei);
  const receipt = await tx.wait();
  return receipt.hash;
}

export async function checkConnection(): Promise<{
  connected: boolean;
  network: string;
  chainId: number | null;
  blockNumber: number | null;
}> {
  try {
    const p = getProvider();
    const network = await p.getNetwork();
    const blockNumber = await p.getBlockNumber();
    return {
      connected: true,
      network: USE_TESTNET ? "Polygon Amoy Testnet" : "Polygon Mainnet",
      chainId: Number(network.chainId),
      blockNumber,
    };
  } catch (err: any) {
    return {
      connected: false,
      network: USE_TESTNET ? "Polygon Amoy Testnet" : "Polygon Mainnet",
      chainId: null,
      blockNumber: null,
    };
  }
}

export function getPolygonscanBaseUrl(): string {
  return USE_TESTNET
    ? "https://amoy.polygonscan.com"
    : "https://polygonscan.com";
}

export async function getRecentBlocks(count: number = 10): Promise<Array<{
  number: number;
  hash: string;
  timestamp: number;
  transactionCount: number;
  miner: string;
  gasUsed: string;
}>> {
  try {
    const p = getProvider();
    const latestBlockNumber = await p.getBlockNumber();
    const blocks = [];
    const fetchCount = Math.min(count, 20);

    for (let i = 0; i < fetchCount; i++) {
      const block = await p.getBlock(latestBlockNumber - i);
      if (block) {
        blocks.push({
          number: block.number,
          hash: block.hash || "",
          timestamp: block.timestamp,
          transactionCount: block.transactions.length,
          miner: block.miner || "0x0000000000000000000000000000000000000000",
          gasUsed: block.gasUsed.toString(),
        });
      }
    }
    return blocks;
  } catch {
    return [];
  }
}

export async function getRecentTransactionsFromBlock(blockNumber: number, limit: number = 5): Promise<Array<{
  hash: string;
  from: string;
  to: string | null;
  value: string;
  blockNumber: number;
}>> {
  try {
    const p = getProvider();
    const block = await p.getBlock(blockNumber, true);
    if (!block || !block.prefetchedTransactions) return [];

    return block.prefetchedTransactions.slice(0, limit).map(tx => ({
      hash: tx.hash,
      from: tx.from,
      to: tx.to,
      value: ethers.formatEther(tx.value),
      blockNumber: tx.blockNumber || blockNumber,
    }));
  } catch {
    return [];
  }
}

export { WDOLLAR2_TOKEN_ABI, USE_TESTNET };

