import { useState } from "react";
import { useAuth } from "@/hooks/use-auth";
import { useConversion } from "@/hooks/use-conversion";
import { CyberCard } from "@/components/CyberCard";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { RefreshCw, CheckCircle2, Clock, AlertTriangle, Ban } from "lucide-react";
import { useLocation } from "wouter";

export default function Conversion() {
  const [_, setLocation] = useLocation();
  const { user } = useAuth();
  const { requests, submitRequest, isSubmitting } = useConversion();

  const [oldAddress, setOldAddress] = useState("");
  const [amount, setAmount] = useState("");

  if (!user) {
    setLocation("/auth");
    return null;
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    submitRequest({
      oldWalletAddress: oldAddress,
      amountClaimed: amount
    });
    setOldAddress("");
    setAmount("");
  };

  const totalConverted = requests?.reduce((sum: number, r: any) => sum + parseFloat(r.amountApproved || "0"), 0) || 0;

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      <div className="text-center mb-12">
        <h1 className="text-4xl font-heading text-accent mb-4" data-testid="text-conversion-title">LEGACY MIGRATION</h1>
        <p className="font-mono text-muted-foreground max-w-2xl mx-auto">
          Convert your original WEBD tokens to the new WDollar 2 chain.
          Swap ratio is 1:1. Old dev wallets are blocked from conversion.
        </p>
      </div>

      <div className="mb-8 p-4 bg-card border border-accent/20 rounded-md font-mono text-sm">
        <div className="flex flex-wrap gap-6 justify-around">
          <div className="text-center">
            <div className="text-muted-foreground text-xs">CONVERTED</div>
            <div className="text-xl text-accent" data-testid="text-total-converted">{totalConverted.toLocaleString()} WEBD</div>
          </div>
          <div className="text-center">
            <div className="text-muted-foreground text-xs">INITIAL CAP</div>
            <div className="text-xl text-primary">1,000,000 WEBD</div>
          </div>
          <div className="text-center">
            <div className="text-muted-foreground text-xs">VESTING LIMIT</div>
            <div className="text-xl text-muted-foreground">500K / 6 months</div>
          </div>
          <div className="text-center">
            <div className="text-muted-foreground text-xs">REMAINING INITIAL</div>
            <div className="text-xl text-primary" data-testid="text-remaining">{Math.max(0, 1000000 - totalConverted).toLocaleString()} WEBD</div>
          </div>
        </div>
      </div>

      <div className="grid md:grid-cols-2 gap-8">

        <CyberCard title="SUBMIT CLAIM">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-mono text-primary/70">OLD WALLET ADDRESS</label>
              <Input
                value={oldAddress}
                onChange={(e) => setOldAddress(e.target.value)}
                className="bg-input border-primary/30 font-mono"
                placeholder="Legacy WEBD address..."
                required
                data-testid="input-old-address"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-mono text-primary/70">AMOUNT TO CLAIM</label>
              <Input
                type="number"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                className="bg-input border-primary/30 font-mono"
                placeholder="0.00"
                required
                data-testid="input-claim-amount"
              />
            </div>

            <div className="p-4 bg-accent/5 border border-accent/20 text-xs font-mono text-muted-foreground rounded-md">
              <AlertTriangle className="w-4 h-4 text-accent inline mr-2" />
              Claims over 1M are subject to 6-month vesting. Old dev wallets are blocked.
            </div>

            <Button type="submit" disabled={isSubmitting} className="w-full btn-gold" data-testid="button-submit-claim">
              {isSubmitting ? "PROCESSING..." : "INITIATE SWAP"}
            </Button>
          </form>
        </CyberCard>

        <CyberCard title="REQUEST HISTORY">
          <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2">
            {requests?.length === 0 && (
              <div className="text-center py-8 text-muted-foreground font-mono text-sm">
                No conversion requests yet.
              </div>
            )}

            {requests?.map((req: any) => (
              <div key={req.id} className="p-4 border border-primary/10 bg-background rounded-md flex justify-between items-center gap-2" data-testid={`conversion-request-${req.id}`}>
                <div className="min-w-0">
                  <div className="text-lg font-mono text-white">{Number(req.amountApproved || req.amountClaimed).toLocaleString()} WEBD</div>
                  <div className="text-xs text-muted-foreground font-mono truncate">{req.oldWalletAddress}</div>
                </div>
                <div className="flex items-center space-x-2 shrink-0">
                  {req.status === 'pending' && <Clock className="w-4 h-4 text-yellow-500" />}
                  {req.status === 'approved' && <CheckCircle2 className="w-4 h-4 text-accent" />}
                  {req.status === 'vesting' && <Clock className="w-4 h-4 text-primary" />}
                  {req.status === 'rejected' && <Ban className="w-4 h-4 text-destructive" />}
                  <span className={`text-xs font-bold uppercase ${
                    req.status === 'approved' ? 'text-accent' :
                    req.status === 'vesting' ? 'text-primary' :
                    req.status === 'rejected' ? 'text-destructive' : 'text-yellow-500'
                  }`}>
                    {req.status}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </CyberCard>
      </div>
    </div>
  );
}

