import { Link, useLocation } from "wouter";
import { useAuth } from "@/hooks/use-auth";
import { Terminal, Cpu, RefreshCw, CreditCard, LogOut, Wallet, Menu, X, KeyRound, ShoppingCart } from "lucide-react";
import { useState } from "react";
import { Button } from "./ui/button";
import logoImg from "@assets/1771108919092_1771109065229.jpg";

export function Navbar() {
  const [location] = useLocation();
  const { user, logout } = useAuth();
  const [isOpen, setIsOpen] = useState(false);

  const isActive = (path: string) => location === path;

  const NavItem = ({ href, children, icon: Icon }: any) => (
    <Link href={href} onClick={() => setIsOpen(false)} className={`
      flex items-center space-x-2 px-4 py-2 font-mono text-sm uppercase tracking-wider border-b-2 transition-all duration-300
      ${isActive(href)
        ? "border-accent text-accent text-gold-glow bg-accent/5"
        : "border-transparent text-muted-foreground hover:text-primary hover:border-primary/50"}
    `}>
      <Icon className="w-4 h-4" />
      <span>{children}</span>
    </Link>
  );

  return (
    <nav className="sticky top-0 z-50 w-full border-b border-primary/20 bg-background/90 backdrop-blur-md">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between gap-4">

        <Link href="/" className="flex items-center space-x-3 group shrink-0">
          <img src={logoImg} alt="WebDollar 2" className="w-12 h-12 rounded-full object-cover" />
          <span className="font-heading font-bold text-xl tracking-wider text-white group-hover:text-accent transition-colors hidden sm:inline">
            W<span className="text-accent">Dollar</span> <span className="text-primary text-sm">2</span>
          </span>
        </Link>

        <div className="hidden md:flex items-center space-x-1 flex-wrap">
          <NavItem href="/" icon={Terminal} data-testid="nav-home">Home</NavItem>
          <NavItem href="/explorer" icon={Cpu} data-testid="nav-explorer">Explorer</NavItem>
          {user && (
            <>
              <NavItem href="/wallet" icon={Wallet} data-testid="nav-wallet">Wallet</NavItem>
              <NavItem href="/addresses" icon={KeyRound} data-testid="nav-addresses">Addresses</NavItem>
              <NavItem href="/conversion" icon={RefreshCw} data-testid="nav-swap">Swap</NavItem>
              <NavItem href="/card" icon={CreditCard} data-testid="nav-card">Card</NavItem>
              <NavItem href="/buy" icon={ShoppingCart} data-testid="nav-buy">Buy</NavItem>
            </>
          )}
        </div>

        <div className="flex items-center space-x-4">
          {user ? (
            <div className="flex items-center space-x-4">
              <span className="hidden md:inline font-mono text-xs text-muted-foreground">
                {user.username}
              </span>
              <Button
                variant="outline"
                size="sm"
                onClick={() => logout()}
                className="hidden md:flex border-destructive/50 text-destructive"
                data-testid="button-logout"
              >
                <LogOut className="w-4 h-4 mr-2" />
                EXIT
              </Button>
            </div>
          ) : (
            <Link href="/auth">
              <Button size="sm" className="btn-neon hidden md:flex" data-testid="button-login">
                Connect
              </Button>
            </Link>
          )}

          <button
            className="md:hidden text-primary"
            onClick={() => setIsOpen(!isOpen)}
            data-testid="button-mobile-menu"
          >
            {isOpen ? <X /> : <Menu />}
          </button>
        </div>
      </div>

      {isOpen && (
        <div className="md:hidden border-b border-primary/20 bg-background p-4 space-y-4">
          <div className="flex flex-col space-y-2">
            <NavItem href="/" icon={Terminal}>Home</NavItem>
            <NavItem href="/explorer" icon={Cpu}>Explorer</NavItem>
            {user && (
              <>
                <NavItem href="/wallet" icon={Wallet}>Wallet</NavItem>
                <NavItem href="/addresses" icon={KeyRound}>Addresses</NavItem>
                <NavItem href="/conversion" icon={RefreshCw}>Swap</NavItem>
                <NavItem href="/card" icon={CreditCard}>Card</NavItem>
                <NavItem href="/buy" icon={ShoppingCart}>Buy</NavItem>
                <Button
                  variant="destructive"
                  className="w-full mt-4 font-mono uppercase"
                  onClick={() => logout()}
                >
                  Terminate Session
                </Button>
              </>
            )}
            {!user && (
              <Link href="/auth">
                <Button className="w-full btn-neon mt-4">Connect Wallet</Button>
              </Link>
            )}
          </div>
        </div>
      )}
    </nav>
  );
}

